struct StateDemo: View {
    @State {isPrivate} var value: {ValueType} = {initialValueExpression}

    var body: some View {
        Toggle("State value", isOn: $value)
    }
}

struct BindingDemo: View {
    @Binding var value: {ValueType}

    var body: some View {
        Toggle("Bound value", isOn: ${useConstant ? .constant(value) : value})
    }
}

// Caller:
// BindingDemo(value: $ownedState)

{isMainActor ? @MainActor : }
@Observable
final class DemoModel {
    var {trackedProperty} = 0
    @ObservationIgnored var cache: [String: Any] = [:]
}

struct ObservableDemo: View {
    @State private var model = DemoModel()

    var body: some View {
        Stepper("Count \(model.{trackedProperty})", value: $model.{trackedProperty})
    }
}

struct BindableDemo: View {
    @Bindable var model: DemoModel   // or: @Environment(DemoModel.self) private var model

    var body: some View {
        // @Bindable var model = model  // when bridging from @Environment
        TextField("Title", text: $model.{boundProperty})
    }
}

struct EnvironmentReadDemo: View {
    @Environment({readByType ? observableType.self : keyPath}) private var value

    var body: some View {
        Text("\(String(describing: value))")
    }
}

// Inspecting the environment inside a custom modifier:
struct DumpEnvironment: ViewModifier {
    @Environment(\.self) private var env
    func body(content: Content) -> some View {
        content.onAppear { print(env) }
    }
}

VStack {
    childViews
}
.environment({keyPath}, {value})

@State private var model = DemoModel()

ContentView()
    .environment({allowNilInjection ? "model as DemoModel?" : "model"})

VStack { childViews }
    .transformEnvironment({keyPath}) { value in
        {transform}
    }

private struct {AccessorKey}: EnvironmentKey {
    static let defaultValue: {valueType} = {defaultValue}
}

extension EnvironmentValues {
    var {accessorName}: {valueType} {
        get { self[{AccessorKey}.self] }
        set { self[{AccessorKey}.self] = newValue }
    }
}

extension {targetStructure} {
    @Entry var {name}: {valueType} = {defaultValue}
}

struct AppStorageDemo: View {
    @AppStorage({key}{store == "standard" ? "" : ", store: \(store)"}) private var value: {ValueType} = {wrappedValue}

    var body: some View {
        Toggle("Persisted", isOn: $value)
    }
}

struct SceneStorageDemo: View {
    @SceneStorage({key}) private var value: {ValueType} = {wrappedValue}

    var body: some View {
        TabView(selection: $value) { tabs }
    }
}

struct FocusStateDemo: View {
    enum Field: Hashable { case username, password }
    @State private var username = ""
    @State private var password = ""
    @FocusState private var focusedField: {valueShape == "Bool" ? "Bool" : "Field?"}

    var body: some View {
        Form {
            TextField("Username", text: $username)
                .{boundModifier == "focused(_:)" ? "focused($focusedField)" : "focused($focusedField, equals: .username)"}
            SecureField("Password", text: $password)
                .focused($focusedField, equals: .password)
            Button("Next") { focusedField = {programmaticFocus} }
        }
    }
}

struct FocusReactiveRow: View {
    @Environment(\.isFocused) private var isFocused

    var body: some View {
        Text("Row")
            .padding()
            .background(isFocused ? Color.accentColor.opacity(0.2) : Color.clear)
    }
}

extension FocusedValues {
    @Entry var selectedDocument: Document?
}

struct DocumentCommands: View {
    @FocusedValue({readByType ? "Document.self" : keyPath}) private var document

    var body: some View {
        Button("Export") { document?.export() }
            .disabled(document == nil)
    }
}

struct TitleCommand: View {
    @FocusedBinding({keyPath}) private var title

    var body: some View {
        TextField("Title", text: Binding($title) ?? .constant(""))
    }
}

struct {KeyName}: PreferenceKey {
    static let defaultValue: {valueType} = {defaultValue}
    static func reduce(value: inout {valueType}, nextValue: () -> {valueType}) {
        {reduceStrategy == "max" ? "value = max(value, nextValue())" : reduceStrategy == "sum" ? "value += nextValue()" : "value = nextValue()"}
    }
}

Text("Item")
    .background(
        GeometryReader { geo in
            Color.clear.preference(key: {key}, value: {value})
        }
    )

VStack { rows }
    .onPreferenceChange({key}) { newValue in
        {perform}
    }

content
    .transformPreference({key}) { value in
        {transform}
    }

RowView()
    .anchorPreference(key: {key}, value: {anchorSource}) { anchor in
        {transform}
    }

Text(now, style: .time)
    .onReceive({publisher}) { output in
        {perform}
    }

struct StateObjectDemo: View {
    @StateObject private var model = ViewModel()

    var body: some View {
        Text(model.title)
    }
}

struct ObservedObjectDemo: View {
    @ObservedObject var model: ViewModel

    var body: some View {
        Toggle("Flag", isOn: $model.{bindingProperty})
    }
}

struct EnvObjectDemo: View {
    @EnvironmentObject private var session: {objectType}

    var body: some View {
        Text(session.username)
    }
}

// Inject upstream:
// ContentView().environmentObject(session)

struct ScaledMetricDemo: View {
    @ScaledMetric(relativeTo: .{relativeTo}) private var iconSize: CGFloat = {wrappedValue}

    var body: some View {
        Image(systemName: "star.fill")
            .resizable()
            .frame(width: iconSize, height: iconSize)
    }
}

struct GestureStateDemo: View {
    @GestureState private var isPressing = {wrappedValue}

    var body: some View {
        Circle()
            .fill(isPressing ? .green : .gray)
            .frame(width: 80, height: 80)
            .gesture(
                LongPressGesture(minimumDuration: 1)
                    .updating($isPressing) { current, state, _ in state = current }
            )
    }
}

struct NamespaceDemo: View {
    @Namespace private var namespace
    @State private var expanded = false

    var body: some View {
        if expanded {
            RoundedRectangle(cornerRadius: 24)
                .matchedGeometryEffect(id: "{matchID}", in: namespace)
                .frame(width: 300, height: 300)
                .onTapGesture { expanded.toggle() }
        } else {
            RoundedRectangle(cornerRadius: 12)
                .matchedGeometryEffect(id: "{matchID}", in: namespace)
                .frame(width: 100, height: 100)
                .onTapGesture { expanded.toggle() }
        }
    }
}

struct ExportCommand: View {
    @FocusedObject private var document: {objectType}?

    var body: some View {
        Button("Export") { document?.export() }
            .disabled(document == nil)
    }
}

